    int top = 0;
    int[] front = new int[n], side = new int[m];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            int h = grid[i][j];
            if (h > 0) top++;
            side[i] = Math.max(side[i], h);
            front[j] = Math.max(front[j], h);
        }
    }
    int total = top;
    for (int x : front) total += x;
    for (int x : side) total += x;
    return total;
}

